animations.cssText:
@keyframes loader { 
  0% { transform: rotateY(0deg) rotateX(0deg); }
  16.6% { transform: rotateY(90deg) rotateX(0deg); }
  33.3% { transform: rotateY(90deg) rotateX(0deg) rotate(90deg); }
  50% { transform: rotateY(180deg) rotateX(0deg) rotate(90deg); }
  66.6% { transform: rotateY(180deg) rotateX(-90deg) rotate(90deg); }
  83.3% { transform: rotateY(270deg) rotateX(-90deg) rotate(90deg); }
  100% { transform: rotateY(270deg) rotateX(-90deg) rotate(90deg) rotateX(90deg); }
}
